import React from 'react';
import ReactStrapSpinner from 'reactstrap/lib/Spinner';
import merge from 'classnames';

import { Image } from 'components';

import { Props } from './Spinner.types';
import styles from './Spinner.module.scss';

export const Spinner: React.FC<Props> = props => {
  const { active, size, unit, classes = {} } = props;
  const dimension: string = `${size}${unit}`;

  return active ? (
    <div className={merge(classes.container, styles.wrapper)}>
      <div className={styles.container}>
        <ReactStrapSpinner
          className={merge(classes.spinner, styles.spinner)}
          style={{ width: dimension, height: dimension }}
        />

        <Image
          src="images/application_logo@2x.png"
          alt="Poku Art Challenge logo"
          className={styles.logo}
        />
      </div>
    </div>
  ) : null;
};

Spinner.defaultProps = {
  active: true,
  size: 60,
  unit: 'px',
};
