import { composeWithDevTools } from 'redux-devtools-extension/developmentOnly';
import { applyMiddleware, createStore, Store, StoreEnhancer } from 'redux';
import createSagaMiddleware from 'redux-saga';

import { RootAction, RootState } from './types';
import { rootReducer } from './reducers';
import { rootSaga } from './sagas';

type AppStore = Store<RootState, RootAction>;

const configureStore = (): AppStore => {
  // Create saga middleware
  const sagaMiddleware = createSagaMiddleware();

  // Gather all middlewares
  const allMiddlewares = [sagaMiddleware];

  // Compose all middlewares
  const middleware: StoreEnhancer = composeWithDevTools(applyMiddleware(...allMiddlewares));

  // Create Redux store
  const store = createStore(rootReducer, middleware);

  // Apply all Sagas
  sagaMiddleware.run(rootSaga);

  return store;
};

export const store = configureStore();
export * from './types';
