import React from 'react';

import { Router } from 'router';
import { Header, Spinner } from 'components';

import { Props } from './ApplicationModule.types';

export class ApplicationModule extends React.Component<Props> {
  componentDidMount(): void {
    this.props.fetchUserData();
  }

  // RENDER

  render() {
    if (this.props.loadingUser) {
      return <Spinner />;
    }

    return (
      <React.Fragment>
        <Header />
        <Router />
      </React.Fragment>
    );
  }
}
