import { connect } from 'react-redux';
import { bindActionCreators, Dispatch } from 'redux';

import { RootState } from 'store';
import { selectRequestStatus } from 'store/reducers/api-requests';
import { userActions, UserActionTypes } from 'store/reducers/user';

import { ApplicationModule as Component } from './ApplicationModule';

const mapStateToProps = (state: RootState) => ({
  loadingUser: selectRequestStatus(state, UserActionTypes.FETCH_USER_DATA__SUCCESS),
});

const mapActionsToProps = (dispatch: Dispatch) =>
  bindActionCreators(
    {
      fetchUserData: userActions.fetchUserDataStart,
    },
    dispatch,
  );

export const ApplicationModule = connect(
  mapStateToProps,
  mapActionsToProps,
)(Component);
