import { Reducer } from 'redux';

import { ApiFailureAction } from 'types';
import { RootAction } from 'store';

import * as helpers from './helpers';
import { ApiRequestsState } from './types';

const initialState: ApiRequestsState = {
  statuses: {},
  errors: {},
};

export const apiRequestsReducer: Reducer<ApiRequestsState, RootAction> = (
  state = initialState,
  action,
) => {
  const { statuses, errors } = state;
  const [requestName, requestStatus] = action.type.split(':');

  switch (requestStatus) {
    case 'start':
      return {
        ...state,
        statuses: helpers.markAsInProgress(statuses, requestName),
        errors: helpers.removeError(errors, requestName),
      };

    case 'success':
      return {
        ...state,
        statuses: helpers.markAsCompleted(statuses, requestName),
        errors: helpers.removeError(errors, requestName),
      };

    case 'failure':
      return {
        ...state,
        statuses: helpers.markAsCompleted(statuses, requestName),
        errors: helpers.storeError(errors, requestName, (action as ApiFailureAction).error),
      };

    default:
      return state;
  }
};
